const about_desc_1$5 = "VizCad was born from the frustration of complex, expensive 3D rendering software. We believe that creating beautiful visualizations of your 3D models shouldn't require extensive knowledge of professional 3D design or expensive software licenses.";
const about_desc_2$5 = "Our mission is to make professional 3D rendering accessible by providing powerful, intuitive tools that work directly in your web browser. Whether you're an engineer, architect, designer, or hobbyist, VizCad gives you the tools to showcase your work beautifully.";
