const contact$5 = {"header":{"title":"Get in","titleAccent":"Touch","subtitle":"Have questions about VizCad? We'd love to hear from you. Send us a message and we'll respond as soon as possible."},"form":{"title":"Send us a message","description":"Fill out the form below and we'll get back to you","name":"Name *","namePlaceholder":"Your name","email":"Email *","emailPlaceholder":"your@email.com","subject":"Subject","subjectPlaceholder":"What's this about?","message":"Message *","messagePlaceholder":"Tell us how we can help you...","sending":"Sending...","send":"Send Message"},"info":{"email":"Email","emailDesc":"We'll respond within 24 hours","phone":"Phone","phoneDesc":"Available during business hours","location":"Location","locationDesc":"Our headquarters","locationValue":"Istanbul, Turkey"},"faq":{"title":"Quick Questions?","desc":"Check our FAQ section for instant answers to common questions.","button":"View FAQ"}};
