const about_desc_1$4 = "VizCad, karmaşık ve pahalı 3D render yazılımlarının yarattığı hayal kırıklığından doğdu. 3D modellerinizin etkileyici görselleştirmelerini oluşturmak, kapsamlı profesyonel 3D tasarım bilgisi ya da pahalı yazılım lisansları gerektirmemeli.";
const about_desc_2$4 = "Misyonumuz; doğrudan web tarayıcınızda çalışan güçlü ve sezgisel araçlar sağlayarak profesyonel 3D render’ı erişilebilir kılmaktır. İster mühendis, mimar, tasarımcı ister hobi meraklısı olun, VizCad çalışmalarınızı etkileyici biçimde sergilemeniz için gerekli araçları sunar.";
const about_card_desc$4 = "VizCad, 3D görselleştirme tutkusunu yıllarca süren 3D CAD tasarım deneyimiyle birleştiren bir mekatronik mühendisinin vizyonudur. Yıllar süren saha deneyiminin ardından, profesyonel araçların herkes için erişilebilir olması gerektiği inancıyla pazarda önemli bir boşluğu tespit etti. Yaratıcı ve teknik topluluğa hizmet etmek için bu platformu sürekli geliştirmeye kararlıyız.";
const footer_company_desc$4 = "Profesyonel 3D görselleştirme basit ve erişilebilir. Çarpıcı render’ları doğrudan tarayıcınızda oluşturun.";
