const contact$4 = {"header":{"title":"İletişime","titleAccent":"Geçin","subtitle":"VizCad hakkında sorularınız mı var? Sizden haber almak isteriz. Bize bir mesaj gönderin, en kısa sürede yanıtlayalım."},"form":{"title":"Bize mesaj gönderin","description":"Aşağıdaki formu doldurun, size geri dönüş yapalım","name":"Ad *","namePlaceholder":"Adınız","email":"E-posta *","emailPlaceholder":"eposta@ornek.com","subject":"Konu","subjectPlaceholder":"Ne hakkında?","message":"Mesaj *","messagePlaceholder":"Size nasıl yardımcı olabiliriz...","sending":"Gönderiliyor...","send":"Mesajı Gönder"},"info":{"email":"E-posta","emailDesc":"24 saat içinde yanıt veriyoruz","phone":"Telefon","phoneDesc":"Mesai saatlerinde ulaşabilirsiniz","location":"Konum","locationDesc":"Merkez ofisimiz","locationValue":"İstanbul, Türkiye"},"faq":{"title":"Hızlı Sorular?","desc":"Sıkça Sorulan Sorular bölümümüzü inceleyin, anında yanıt bulun.","button":"SSS’yi Görüntüle"}};
const footer_copyright$4 = "© 2025 VizCad. Tüm hakları saklıdır.";
const faq$4 = {"header":{"title":"Sıkça Sorulan","titleAccent":"Sorular","subtitle":"VizCAD'in özellikleri, yetenekleri ve 3D görselleştirme platformumuzdan en iyi şekilde nasıl yararlanabileceğinize dair yaygın soruların cevaplarını bulun."},"card":{"title":"Genel Sorular","description":"Cevabı görmek için aşağıdaki sorulardan birine tıklayın"},"questions":{"what-is-vizcad":{"question":"VizCAD nedir?","answer":"VizCAD, mevcut CAD tasarımlarınızı karmaşık yazılımlara ihtiyaç duymadan, web üzerinden kolayca görselleştirmenizi sağlayan bir platformdur. Mühendisler, mimarlar ve ürün tasarımcıları gibi profesyonellerin, tasarımlarını hızlı ve profesyonel bir şekilde görselleştirmelerine yardımcı olur."},"supported-browsers":{"question":"VizCAD'i kullanmak için hangi tarayıcıları kullanmalıyım?","answer":"VizCAD, WebGL desteğine sahip tüm modern web tarayıcılarında çalışır. Bilgisayar, tablet veya telefon gibi herhangi bir cihazdan erişim sağlayabilirsiniz."},"file-formats":{"question":"VizCAD hangi dosya formatlarını destekliyor?","answer":"VizCAD şu an için STL, OBJ, PLY ve 3MF dosya formatlarını desteklemektedir."},"getting-started":{"question":"VizCAD'i kullanmaya nasıl başlayabilirim?","answer":"VizCAD'i kullanmaya başlamak oldukça kolay. Doğrudan tarayıcınız üzerinden STL, OBJ, PLY veya 3MF dosyanızı sürükleyip bırakmanız yeterlidir. Herhangi bir yazılım yüklemenize veya hesap oluşturmanıza gerek yoktur."},"system-requirements":{"question":"Sistem gereksinimleri nelerdir?","answer":"Uygulama tamamen web tarayıcınızda çalıştığı için özel bir kurulum gerektirmez. Pürüzsüz bir deneyim için WebGL desteğine sahip modern bir tarayıcı yeterlidir. Performans, tarayıcının ve cihazın özelliklerine göre değişiklik gösterebilir."},"collaboration":{"question":"VizCAD projelerinde başkalarıyla iş birliği yapabilir miyim?","answer":"VizCAD, bir ekip çalışması sırasında tasarım dosyalarına erişim sorununu çözmek amacıyla ortaya çıkmıştır. Uygulama, tasarımları herkes için erişilebilir kılsa da, şu an için dahili iş birliği özelliklerine dair bir bilgi bulunmamaktadır."},"is-it-free":{"question":"VizCAD'i kullanmak ücretsiz mi?","answer":"Evet, VizCAD Freemium bir modelle tasarlanmıştır. Bu model sayesinde, temel özellikleri ücretsiz olarak kullanabilirsiniz. Daha gelişmiş araçlara ve özelliklere erişim için ise premium abonelik seçenekleri sunulacaktır."},"data-security":{"question":"VizCAD'deki verilerim ne kadar güvenli?","answer":"VizCAD, bulut tabanlı bir sistem yerine istemci tarafında (client-side) görüntüleme yapar. Bu, verilerinizin mümkün olduğunca yerel olarak, yani tarayıcınızda işlendiği anlamına gelir. Bu yaklaşım, dosyalarınızın harici sunucularda saklanma ihtiyacını ortadan kaldırarak güvenliği artırır."},"how-is-it-different":{"question":"VizCAD, AutoCAD gibi rakiplerden hangi yönleriyle ayrılıyor?","answer":"VizCAD'in en büyük farkı, Autodesk gibi karmaşık ve pahalı yazılımların aksine, profesyonel bir hizmeti kullanıcı dostu bir arayüzle sunmasıdır. Piyasada bulunan amatör seviye CAD görüntüleyicilerinden farklı olarak, VizCAD ile tüm kullanıcılar, karmaşık yazılım bilgisine ihtiyaç duymadan tasarımlarını yüksek kalitede görsellere dönüştürebilir."},"development-process":{"question":"VizCAD'in gelişim süreci nasıl oldu ve en önemli dönüm noktaları nelerdi?","answer":"VizCAD'in ilk MVP (Minimum Viable Product) sürümü, yalnızca bir CAD dosyası önizleme aracıydı. Kullanıcılardan gelen geri bildirimlerle, teknik özelliklerden ziyade görselleştirme araçlarına odaklanma kararı alındı. Bu dönüşüm, ürünü basit bir önizleme aracından güçlü bir görselleştirme platformuna dönüştürerek ürün yol haritasının yeniden çizilmesini sağladı."}}};
