const features_card_4_title$3 = "Studioszenen";
const features_card_4_desc$3 = "Professionelle Beleuchtungsvoreinstellungen, darunter schlichtes Weiß, 3-Punkt-Beleuchtung, warmes Studio und benutzerdefinierte Hintergrundfarben für saubere Präsentationen.";
const features_card_5_title$3 = "Kamerasteuerung";
const features_card_5_desc$3 = "Mehrere Ansichtsvoreinstellungen (vorne, hinten, links, rechts, oben, unten, isometrisch) mit Zoomsteuerung und Kamera-Reset-Funktion.";
const features_card_6_title$3 = "Plattformübergreifend";
const features_card_6_desc$3 = "Funktioniert auf jedem Gerät mit einem modernen Webbrowser. Desktop, Tablet oder Mobilgerät - Ihre 3D-Modelle sind immer zugänglich.";
