const about_title$3 = "3D-Visualisierung für alle zugänglich machen";
const about_desc_1$3 = "VizCad entstand aus der Frustration über komplexe, teure 3D-Rendering-Software. Wir glauben, dass die Erstellung schöner Visualisierungen Ihrer 3D-Modelle kein umfangreiches Wissen über professionelles 3D-Design oder teure Softwarelizenzen erfordern sollte.";
const about_desc_2$3 = "Unsere Mission ist es, professionelles 3D-Rendering zugänglich zu machen, indem wir leistungsstarke, intuitive Tools bereitstellen, die direkt in Ihrem Webbrowser funktionieren. Egal, ob Sie Ingenieur, Architekt, Designer oder Hobbyist sind, VizCad gibt Ihnen die Werkzeuge an die Hand, um Ihre Arbeit auf schöne Weise zu präsentieren.";
const about_card_desc$3 = "VizCad ist die Vision eines Mechatronik-Ingenieurs, der eine Leidenschaft für 3D-Visualisierung mit jahrelanger Erfahrung im 3D-CAD-Design verbindet. Nach jahrelanger praktischer Arbeit wurde eine erhebliche Marktlücke erkannt, mit der Überzeugung, dass professionelle Tools für jedermann zugänglich sein sollten. Wir sind bestrebt, diese Plattform kontinuierlich weiterzuentwickeln, um der kreativen und technischen Community zu dienen.";
const footer_company_desc$3 = "Professionelle 3D-Visualisierung einfach und zugänglich gemacht. Erstellen Sie atemberaubende Renderings direkt in Ihrem Browser.";
const footer_quick_links$3 = "Schnelllinks";
const footer_contact$3 = "Kontakt";
