const footer_phone$3 = "+90 (536) 247-1019";
const footer_location$3 = "Istanbul, Türkei";
const contact$3 = {"header":{"title":"Kontakt","titleAccent":"aufnehmen","subtitle":"Haben Sie Fragen zu VizCad? Wir würden uns freuen, von Ihnen zu hören. Senden Sie uns eine Nachricht und wir werden so schnell wie möglich antworten."},"form":{"title":"Senden Sie uns eine Nachricht","description":"Füllen Sie das untenstehende Formular aus und wir melden uns bei Ihnen","name":"Name *","namePlaceholder":"Ihr Name","email":"E-Mail *","emailPlaceholder":"ihre@email.com","subject":"Betreff","subjectPlaceholder":"Worum geht es?","message":"Nachricht *","messagePlaceholder":"Erzählen Sie uns, wie wir Ihnen helfen können...","sending":"Wird gesendet...","send":"Nachricht senden"},"info":{"email":"E-Mail","emailDesc":"Wir antworten innerhalb von 24 Stunden","phone":"Telefon","phoneDesc":"Während der Geschäftszeiten erreichbar","location":"Standort","locationDesc":"Unser Hauptsitz","locationValue":"Istanbul, Türkei"},"faq":{"title":"Schnelle Fragen?","desc":"Schauen Sie in unserem FAQ-Bereich nach, um sofort Antworten auf häufige Fragen zu finden.","button":"FAQ ansehen"}};
const footer_copyright$3 = "© 2025 VizCad. Alle Rechte vorbehalten.";
const faq$3 = {"header":{"title":"Häufig gestellte","titleAccent":"Fragen","subtitle":"Hier finden Sie Antworten auf häufig gestellte Fragen zu den Funktionen, Fähigkeiten und der optimalen Nutzung unserer 3D-Visualisierungsplattform."},"card":{"title":"Häufige Fragen","description":"Klicken Sie auf eine Frage, um die Antwort zu sehen"},"questions":{"what-is-vizcad":{"question":"Was ist VizCAD?","answer":"VizCAD ist eine Plattform, mit der Sie Ihre bestehenden CAD-Designs einfach über das Web visualisieren können, ohne dass eine komplexe Software erforderlich ist. Es hilft Fachleuten wie Ingenieuren, Architekten und Produktdesignern, ihre Designs schnell und professionell zu visualisieren."},"supported-browsers":{"question":"Welche Browser sollte ich für VizCAD verwenden?","answer":"VizCAD funktioniert auf allen modernen Webbrowsern mit WebGL-Unterstützung. Sie können von jedem Gerät wie einem Computer, Tablet oder Mobiltelefon darauf zugreifen."},"file-formats":{"question":"Welche Dateiformate unterstützt VizCAD?","answer":"VizCAD unterstützt derzeit die Dateiformate STL, OBJ, PLY und 3MF."},"getting-started":{"question":"Wie starte ich mit VizCAD?","answer":"Der Einstieg in VizCAD ist ganz einfach. Sie müssen nur Ihre STL-, OBJ-, PLY- oder 3MF-Datei per Drag & Drop direkt in Ihren Browser ziehen. Keine Softwareinstallation oder Kontoerstellung erforderlich."},"system-requirements":{"question":"Was sind die Systemanforderungen?","answer":"Die Anwendung läuft vollständig in Ihrem Webbrowser, daher ist keine spezielle Installation erforderlich. Ein moderner Browser mit WebGL-Unterstützung reicht für eine reibungslose Erfahrung aus. Die Leistung kann je nach Browser und Gerätespezifikationen variieren."},"collaboration":{"question":"Kann ich mit anderen an VizCAD-Projekten zusammenarbeiten?","answer":"VizCAD entstand, um das Problem des Zugriffs auf Designdateien bei der Teamarbeit zu lösen. Während die Anwendung Designs für jeden zugänglich macht, gibt es derzeit keine Informationen über integrierte Kollaborationsfunktionen."},"is-it-free":{"question":"Ist VizCAD kostenlos?","answer":"Ja, VizCAD ist mit einem Freemium-Modell konzipiert. Mit diesem Modell können Sie die Kernfunktionen kostenlos nutzen. Premium-Abonnementoptionen werden angeboten, um Zugang zu fortschrittlicheren Tools und Funktionen zu erhalten."},"data-security":{"question":"Wie sicher sind meine Daten in VizCAD?","answer":"VizCAD führt clientseitiges Rendering anstelle eines cloudbasierten Systems durch. Das bedeutet, dass Ihre Daten so weit wie möglich lokal, in Ihrem Browser, verarbeitet werden. Dieser Ansatz erhöht die Sicherheit, indem die Notwendigkeit entfällt, Ihre Dateien auf externen Servern zu speichern."},"how-is-it-different":{"question":"Wie unterscheidet sich VizCAD von Konkurrenten wie AutoCAD?","answer":"Der größte Unterschied von VizCAD besteht darin, dass es einen professionellen Service mit einer benutzerfreundlichen Oberfläche bietet, im Gegensatz zu komplexer und teurer Software wie Autodesk. Im Gegensatz zu CAD-Viewern für Amateure auf dem Markt ermöglicht VizCAD allen Benutzern, ihre Designs in hochwertige Visualisierungen umzuwandeln, ohne umfangreiche Softwarekenntnisse zu benötigen."},"development-process":{"question":"Wie sah der Entwicklungsprozess von VizCAD aus und was waren die wichtigsten Wendepunkte?","answer":"Die erste MVP-Version (Minimum Viable Product) von VizCAD war nur ein CAD-Datei-Vorschau-Tool. Basierend auf dem Feedback der Benutzer wurde beschlossen, sich auf Visualisierungswerkzeuge statt auf technische Funktionen zu konzentrieren. Diese Transformation verwandelte das Produkt von einem einfachen Vorschau-Tool in eine leistungsstarke Visualisierungsplattform und führte zu einer Neugestaltung der Produkt-Roadmap."}}};
