const features_card_1_desc$2 = "Arrastre y suelte sus archivos STL, OBJ, PLY o 3MF directamente en el navegador. No se requiere instalación de software ni creación de cuenta.";
const features_card_2_title$2 = "Controles de visualización";
const features_card_2_desc$2 = "Alterne el modo de wireframe, sombreado suave, vistas de perspectiva/ortográficas y ejes de coordenadas. Visualización en tiempo real con retroalimentación instantánea.";
const features_card_3_title$2 = "Rendimiento rápido";
const features_card_3_desc$2 = "Renderizado WebGL optimizado para una interacción fluida. Funciona directamente en su navegador sin necesidad de plugins o descargas.";
const features_card_4_title$2 = "Escenas de estudio";
const features_card_4_desc$2 = "Ajustes preestablecidos de iluminación profesional que incluyen blanco liso, iluminación de 3 puntos, estudio cálido y colores de fondo personalizados para presentaciones limpias.";
const features_card_5_title$2 = "Navegación de cámara";
const features_card_5_desc$2 = "Múltiples vistas preestablecidas (frontal, trasera, izquierda, derecha, superior, inferior, isométrica) con controles de zoom y función de reinicio de cámara.";
const features_card_6_title$2 = "Multiplataforma";
const features_card_6_desc$2 = "Funciona en cualquier dispositivo con un navegador web moderno. Escritorio, tablet o móvil: sus modelos 3D siempre estarán accesibles.";
const features_coming_title$2 = "Funciones avanzadas próximamente";
