const contact$2 = {"header":{"title":"Ponerse en","titleAccent":"contacto","subtitle":"¿Tiene preguntas sobre VizCad? Nos encantaría saber de usted. Envíenos un mensaje y le responderemos lo antes posible."},"form":{"title":"Envíanos un mensaje","description":"Rellene el siguiente formulario y nos pondremos en contacto con usted","name":"Nombre *","namePlaceholder":"Su nombre","email":"Email *","emailPlaceholder":"su@email.com","subject":"Asunto","subjectPlaceholder":"¿De qué se trata?","message":"Mensaje *","messagePlaceholder":"Díganos cómo podemos ayudarle...","sending":"Enviando...","send":"Enviar mensaje"},"info":{"email":"Email","emailDesc":"Le responderemos en 24 horas","phone":"Teléfono","phoneDesc":"Disponible durante el horario comercial","location":"Ubicación","locationDesc":"Nuestra sede central","locationValue":"Estambul, Turquía"},"faq":{"title":"¿Preguntas rápidas?","desc":"Consulte nuestra sección de preguntas frecuentes para obtener respuestas instantáneas a preguntas comunes.","button":"Ver preguntas frecuentes"}};
const footer_copyright$2 = "© 2025 VizCad. Todos los derechos reservados.";
const faq$2 = {"header":{"title":"Preguntas","titleAccent":"frecuentes","subtitle":"Encuentre respuestas a preguntas comunes sobre las características, capacidades y cómo aprovechar al máximo nuestra plataforma de visualización 3D de VizCAD."},"card":{"title":"Preguntas comunes","description":"Haga clic en cualquier pregunta a continuación para ver la respuesta"},"questions":{"what-is-vizcad":{"question":"¿Qué es VizCAD?","answer":"VizCAD es una plataforma que le permite visualizar fácilmente sus diseños CAD existentes a través de la web sin la necesidad de software complejo. Ayuda a profesionales como ingenieros, arquitectos y diseñadores de productos a visualizar sus diseños de forma rápida y profesional."},"supported-browsers":{"question":"¿Qué navegadores debo usar para VizCAD?","answer":"VizCAD funciona en todos los navegadores web modernos con soporte WebGL. Puede acceder a él desde cualquier dispositivo, como una computadora, tablet o teléfono móvil."},"file-formats":{"question":"¿Qué formatos de archivo admite VizCAD?","answer":"Actualmente, VizCAD admite los formatos de archivo STL, OBJ, PLY y 3MF."},"getting-started":{"question":"¿Cómo empiezo a usar VizCAD?","answer":"Empezar a usar VizCAD es bastante fácil. Solo necesita arrastrar y soltar su archivo STL, OBJ, PLY o 3MF directamente en su navegador. No se requiere instalación de software ni creación de cuenta."},"system-requirements":{"question":"¿Cuáles son los requisitos del sistema?","answer":"La aplicación se ejecuta íntegramente en su navegador web, por lo que no se requiere una instalación especial. Un navegador moderno con soporte WebGL es suficiente para una experiencia fluida. El rendimiento puede variar según el navegador y las especificaciones del dispositivo."},"collaboration":{"question":"¿Puedo colaborar con otros en proyectos de VizCAD?","answer":"VizCAD surgió para resolver el problema de acceder a los archivos de diseño durante el trabajo en equipo. Si bien la aplicación hace que los diseños sean accesibles para todos, actualmente no hay información sobre funciones de colaboración integradas."},"is-it-free":{"question":"¿Es VizCAD de uso gratuito?","answer":"Sí, VizCAD está diseñado con un modelo Freemium. Con este modelo, puede usar las funciones principales de forma gratuita. Se ofrecerán opciones de suscripción Premium para acceder a herramientas y funciones más avanzadas."},"data-security":{"question":"¿Qué tan seguros están mis datos en VizCAD?","answer":"VizCAD realiza un renderizado del lado del cliente en lugar de utilizar un sistema basado en la nube. Esto significa que sus datos se procesan localmente, en su navegador, en la medida de lo posible. Este enfoque aumenta la seguridad al eliminar la necesidad de almacenar sus archivos en servidores externos."},"how-is-it-different":{"question":"¿En qué se diferencia VizCAD de competidores como AutoCAD?","answer":"La mayor diferencia de VizCAD es que ofrece un servicio profesional con una interfaz fácil de usar, a diferencia de software complejo y costoso como Autodesk. A diferencia de los visores CAD de nivel amateur en el mercado, VizCAD permite a todos los usuarios convertir sus diseños en imágenes de alta calidad sin necesidad de un amplio conocimiento de software."},"development-process":{"question":"¿Cómo fue el proceso de desarrollo de VizCAD y cuáles fueron los principales puntos de inflexión?","answer":"La versión inicial de MVP (Producto Mínimo Viable) de VizCAD era solo una herramienta de vista previa de archivos CAD. Según los comentarios de los usuarios, se decidió centrarse en las herramientas de visualización en lugar de las funciones técnicas. Esta transformación convirtió el producto de una simple herramienta de vista previa en una poderosa plataforma de visualización y condujo a un rediseño del plan de desarrollo del producto."}}};
