const features_card_3_title$1 = "Performances rapides";
const features_card_3_desc$1 = "Rendu WebGL optimisé pour une interaction fluide. Fonctionne directement dans votre navigateur sans plugins ni téléchargements requis.";
const features_card_4_title$1 = "Scènes de studio";
const features_card_4_desc$1 = "Préréglages d'éclairage professionnels, y compris blanc uni, éclairage à 3 points, studio chaud et couleurs d'arrière-plan personnalisées pour des présentations claires.";
const features_card_5_title$1 = "Navigation de la caméra";
const features_card_5_desc$1 = "Plusieurs préréglages de vue (avant, arrière, gauche, droite, haut, bas, isométrique) avec des commandes de zoom et une fonctionnalité de réinitialisation de la caméra.";
const features_card_6_title$1 = "Multiplateforme";
const features_card_6_desc$1 = "Fonctionne sur n'importe quel appareil doté d'un navigateur web moderne. Ordinateur de bureau, tablette ou mobile, vos modèles 3D sont toujours accessibles.";
const features_coming_title$1 = "Fonctionnalités avancées à venir";
