const contact$1 = {"header":{"title":"Nous","titleAccent":"contacter","subtitle":"Vous avez des questions sur VizCad ? Nous serions ravis de vous entendre. Envoyez-nous un message et nous vous répondrons dès que possible."},"form":{"title":"Envoyez-nous un message","description":"Remplissez le formulaire ci-dessous et nous vous répondrons","name":"Nom *","namePlaceholder":"Votre nom","email":"Email *","emailPlaceholder":"votre@email.com","subject":"Sujet","subjectPlaceholder":"De quoi s'agit-il ?","message":"Message *","messagePlaceholder":"Dites-nous comment nous pouvons vous aider...","sending":"Envoi en cours...","send":"Envoyer le message"},"info":{"email":"Email","emailDesc":"Nous vous répondrons dans les 24 heures","phone":"Téléphone","phoneDesc":"Disponible pendant les heures de bureau","location":"Lieu","locationDesc":"Notre siège social","locationValue":"Istanbul, Turquie"},"faq":{"title":"Des questions rapides ?","desc":"Consultez notre section FAQ pour obtenir des réponses instantanées aux questions courantes.","button":"Voir la FAQ"}};
const footer_copyright$1 = "© 2025 VizCad. Tous droits réservés.";
const faq$1 = {"header":{"title":"Foire aux","titleAccent":"questions","subtitle":"Trouvez des réponses aux questions courantes sur les fonctionnalités de VizCAD, ses capacités et comment tirer le meilleur parti de notre plateforme de visualisation 3D."},"card":{"title":"Questions courantes","description":"Cliquez sur n'importe quelle question ci-dessous pour voir la réponse"},"questions":{"what-is-vizcad":{"question":"Qu'est-ce que VizCAD ?","answer":"VizCAD est une plateforme qui vous permet de visualiser facilement vos conceptions CAO existantes via le web sans avoir besoin de logiciels complexes. Il aide les professionnels comme les ingénieurs, les architectes et les concepteurs de produits à visualiser rapidement et professionnellement leurs conceptions."},"supported-browsers":{"question":"Quels navigateurs dois-je utiliser pour VizCAD ?","answer":"VizCAD fonctionne sur tous les navigateurs web modernes avec prise en charge de WebGL. Vous pouvez y accéder depuis n'importe quel appareil, comme un ordinateur, une tablette ou un téléphone portable."},"file-formats":{"question":"Quels formats de fichiers VizCAD prend-il en charge ?","answer":"VizCAD prend actuellement en charge les formats de fichiers STL, OBJ, PLY et 3MF."},"getting-started":{"question":"Comment puis-je commencer avec VizCAD ?","answer":"Commencer avec VizCAD est assez facile. Il vous suffit de glisser-déposer votre fichier STL, OBJ, PLY ou 3MF directement dans votre navigateur. Aucune installation de logiciel ni création de compte n'est requise."},"system-requirements":{"question":"Quelles sont les configurations requises ?","answer":"L'application fonctionne entièrement dans votre navigateur web, donc aucune installation spéciale n'est requise. Un navigateur moderne avec prise en charge de WebGL est suffisant pour une expérience fluide. Les performances peuvent varier en fonction du navigateur et des spécifications de l'appareil."},"collaboration":{"question":"Puis-je collaborer avec d'autres sur des projets VizCAD ?","answer":"VizCAD a vu le jour pour résoudre le problème de l'accès aux fichiers de conception lors du travail d'équipe. Bien que l'application rende les conceptions accessibles à tous, il n'y a actuellement aucune information sur les fonctionnalités de collaboration intégrées."},"is-it-free":{"question":"Est-ce que VizCAD est gratuit ?","answer":"Oui, VizCAD est conçu avec un modèle Freemium. Avec ce modèle, vous pouvez utiliser les fonctionnalités de base gratuitement. Des options d'abonnement Premium seront proposées pour accéder à des outils et fonctionnalités plus avancés."},"data-security":{"question":"Quelle est la sécurité de mes données dans VizCAD ?","answer":"VizCAD effectue un rendu côté client au lieu d'utiliser un système basé sur le cloud. Cela signifie que vos données sont traitées localement, dans votre navigateur, autant que possible. Cette approche augmente la sécurité en éliminant le besoin de stocker vos fichiers sur des serveurs externes."},"how-is-it-different":{"question":"En quoi VizCAD est-il différent de concurrents comme AutoCAD ?","answer":"La plus grande différence de VizCAD est qu'il offre un service professionnel avec une interface conviviale, contrairement aux logiciels complexes et coûteux comme Autodesk. Contrairement aux visualiseurs CAO de niveau amateur sur le marché, VizCAD permet à tous les utilisateurs de convertir leurs conceptions en visuels de haute qualité sans avoir besoin de connaissances logicielles approfondies."},"development-process":{"question":"Quel a été le processus de développement de VizCAD et quels ont été les principaux tournants ?","answer":"La version initiale de l'MVP (Produit Minimum Viable) de VizCAD n'était qu'un outil de prévisualisation de fichiers CAO. Sur la base des commentaires des utilisateurs, la décision a été prise de se concentrer sur les outils de visualisation plutôt que sur les fonctionnalités techniques. Cette transformation a fait passer le produit d'un simple outil de prévisualisation à une puissante plateforme de visualisation et a conduit à un remaniement de la feuille de route du produit."}}};
