const about_title = "3D विज़ुअलाइज़ेशन को सभी के लिए सुलभ बनाना";
const about_desc_1 = "VizCad जटिल, महंगे 3D रेंडरिंग सॉफ़्टवेयर की निराशा से पैदा हुआ था। हम मानते हैं कि आपके 3D मॉडल के सुंदर विज़ुअलाइज़ेशन बनाने के लिए पेशेवर 3D डिज़ाइन या महंगे सॉफ़्टवेयर लाइसेंस के व्यापक ज्ञान की आवश्यकता नहीं होनी चाहिए।";
const about_desc_2 = "हमारा मिशन शक्तिशाली, सहज ज्ञान युक्त टूल प्रदान करके पेशेवर 3D रेंडरिंग को सुलभ बनाना है जो सीधे आपके वेब ब्राउज़र में काम करते हैं। चाहे आप एक इंजीनियर, आर्किटेक्ट, डिज़ाइनर, या शौक़ीन हों, VizCad आपको अपने काम को खूबसूरती से प्रदर्शित करने के लिए टूल देता है।";
const about_card_desc = "VizCad एक मेकाट्रॉनिक्स इंजीनियर की दृष्टि है जो 3D विज़ुअलाइज़ेशन के जुनून को 3D CAD डिज़ाइन में वर्षों के अनुभव के साथ जोड़ता है। वर्षों के व्यावहारिक काम के बाद, यह विश्वास के साथ बाजार में एक महत्वपूर्ण अंतर की पहचान की गई कि पेशेवर उपकरण सभी के लिए सुलभ होने चाहिए। हम रचनात्मक और तकनीकी समुदाय की सेवा के लिए इस प्लेटफ़ॉर्म को लगातार विकसित करने के लिए प्रतिबद्ध हैं।";
const footer_company_desc = "पेशेवर 3D विज़ुअलाइज़ेशन को सरल और सुलभ बनाया गया। सीधे अपने ब्राउज़र में शानदार रेंडर बनाएं।";
