const faq = {"header":{"title":"अक्सर पूछे जाने वाले","titleAccent":"प्रश्न","subtitle":"VizCAD की विशेषताओं, क्षमताओं और हमारे 3D विज़ुअलाइज़ेशन प्लेटफ़ॉर्म का अधिकतम लाभ कैसे उठाएं, इस बारे में सामान्य प्रश्नों के उत्तर खोजें।"},"card":{"title":"सामान्य प्रश्न","description":"उत्तर देखने के लिए नीचे दिए गए किसी भी प्रश्न पर क्लिक करें"},"questions":{"what-is-vizcad":{"question":"VizCAD क्या है?","answer":"VizCAD एक ऐसा प्लेटफ़ॉर्म है जो आपको जटिल सॉफ़्टवेयर की आवश्यकता के बिना वेब के माध्यम से अपने मौजूदा CAD डिज़ाइनों को आसानी से देखने की अनुमति देता है। यह इंजीनियरों, वास्तुकारों और उत्पाद डिज़ाइनरों जैसे पेशेवरों को अपने डिज़ाइनों को जल्दी और पेशेवर रूप से देखने में मदद करता है।"},"supported-browsers":{"question":"मुझे VizCAD के लिए कौन से ब्राउज़र का उपयोग करना चाहिए?","answer":"VizCAD WebGL समर्थन वाले सभी आधुनिक वेब ब्राउज़रों पर काम करता है। आप इसे किसी भी डिवाइस जैसे कंप्यूटर, टैबलेट या मोबाइल फ़ोन से एक्सेस कर सकते हैं।"},"file-formats":{"question":"VizCAD किन फ़ाइल स्वरूपों का समर्थन करता है?","answer":"VizCAD वर्तमान में STL, OBJ, PLY, और 3MF फ़ाइल स्वरूपों का समर्थन करता है।"},"getting-started":{"question":"मैं VizCAD के साथ कैसे शुरुआत करूं?","answer":"VizCAD के साथ शुरुआत करना काफी आसान है। आपको बस अपनी STL, OBJ, PLY, या 3MF फ़ाइल को सीधे अपने ब्राउज़र में ड्रैग और ड्रॉप करना होगा। किसी सॉफ़्टवेयर इंस्टॉलेशन या खाता बनाने की आवश्यकता नहीं है।"},"system-requirements":{"question":"सिस्टम आवश्यकताएँ क्या हैं?","answer":"एप्लिकेशन पूरी तरह से आपके वेब ब्राउज़र में चलता है, इसलिए किसी विशेष इंस्टॉलेशन की आवश्यकता नहीं है। एक सुगम अनुभव के लिए WebGL समर्थन वाला एक आधुनिक ब्राउज़र पर्याप्त है। प्रदर्शन ब्राउज़र और डिवाइस विनिर्देशों के आधार पर भिन्न हो सकता है।"},"collaboration":{"question":"क्या मैं VizCAD परियोजनाओं पर दूसरों के साथ सहयोग कर सकता हूँ?","answer":"VizCAD टीम वर्क के दौरान डिज़ाइन फ़ाइलों तक पहुँचने की समस्या को हल करने के लिए उभरा। जबकि एप्लिकेशन डिज़ाइनों को सभी के लिए सुलभ बनाता है, वर्तमान में अंतर्निहित सहयोग सुविधाओं के बारे में कोई जानकारी नहीं है।"},"is-it-free":{"question":"क्या VizCAD का उपयोग करना मुफ़्त है?","answer":"हाँ, VizCAD को एक फ्रीमियम मॉडल के साथ डिज़ाइन किया गया है। इस मॉडल के साथ, आप मुख्य सुविधाओं का मुफ़्त में उपयोग कर सकते हैं। अधिक उन्नत टूल और सुविधाओं तक पहुँच के लिए प्रीमियम सदस्यता विकल्प पेश किए जाएंगे।"},"data-security":{"question":"VizCAD में मेरा डेटा कितना सुरक्षित है?","answer":"VizCAD क्लाउड-आधारित सिस्टम का उपयोग करने के बजाय क्लाइंट-साइड रेंडरिंग करता है। इसका मतलब है कि आपका डेटा स्थानीय रूप से, आपके ब्राउज़र में, जितना संभव हो उतना संसाधित होता है। यह दृष्टिकोण बाहरी सर्वर पर आपकी फ़ाइलों को संग्रहीत करने की आवश्यकता को समाप्त करके सुरक्षा बढ़ाता है।"},"how-is-it-different":{"question":"VizCAD, AutoCAD जैसे प्रतिस्पर्धियों से कैसे अलग है?","answer":"VizCAD का सबसे बड़ा अंतर यह है कि यह Autodesk जैसे जटिल और महंगे सॉफ़्टवेयर के विपरीत, उपयोगकर्ता के अनुकूल इंटरफ़ेस के साथ एक पेशेवर सेवा प्रदान करता है। बाजार में शौकिया स्तर के CAD व्यूअर्स के विपरीत, VizCAD सभी उपयोगकर्ताओं को व्यापक सॉफ़्टवेयर ज्ञान की आवश्यकता के बिना अपने डिज़ाइनों को उच्च-गुणवत्ता वाले विज़ुअल्स में बदलने की अनुमति देता है।"},"development-process":{"question":"VizCAD का विकास प्रक्रिया कैसी थी और मुख्य मोड़ क्या थे?","answer":"VizCAD का प्रारंभिक MVP (न्यूनतम व्यवहार्य उत्पाद) संस्करण केवल एक CAD फ़ाइल पूर्वावलोकन टूल था। उपयोगकर्ता की प्रतिक्रिया के आधार पर, तकनीकी सुविधाओं के बजाय विज़ुअलाइज़ेशन टूल पर ध्यान केंद्रित करने का निर्णय लिया गया। इस परिवर्तन ने उत्पाद को एक साधारण पूर्वावलोकन टूल से एक शक्तिशाली विज़ुअलाइज़ेशन प्लेटफ़ॉर्म में बदल दिया और उत्पाद रोडमैप के पुन: डिज़ाइन का नेतृत्व किया।"}}};
